VALUES
  ('cpa-moex-01301', 'cpa', 'cpa-moex-103-78566e18', 'sub-cpa-01', NULL, 'single_choice', '龍潭公司承租一座購物中心，包含土地及地上建物，有關租賃分類之下列敘述，何者錯誤？', '["最低租賃給付應按租賃開始日土地及建築物之公允價值相對比例分攤予土地及建築物", "若租賃給付無法可靠地分攤至此兩項要素，則整體租賃應分類為融資租賃，除非二項要素均明顯 符合營業租賃標準", "如土地要素之原始認列金額不重大，則土地及建築物可按單一項目處理", "若龍潭公司將該購物中心分類為投資性不動產，則應以融資租賃方式處理"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:14+00:00", "source_pdf_sha1": "5ea07b090de5", "answer_pdf_sha1": "9924e7044cbb", "source_family": "moex-gov-tw", "moex": {"exam_code": "103130", "c": "803", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "103", "exam_name": "103年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01302', 'cpa', 'cpa-moex-103-78566e18', 'sub-cpa-01', NULL, 'single_choice', '丁公司採確定福利退休計畫，20X7年底退休計畫相關項目如下： 確定福利義務現值  $8,000,000 計畫資產公允價值  5,000,000 未攤銷前期服務成本  1,000,000 未攤銷精算利益  2,500,000 應計退休金負債  4,500,000 該公司於20X8年初以計畫資產$1,000,000購買年金合約，以清償全部既得給付義務$l,000,000。則購 買年金合約以清償既得福利義務之事項，對20X8年應計退休金負債影響為何？', '["增加$187,500", "增加$1,000,000", "減少$187,500", "減少$1,000,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:14+00:00", "source_pdf_sha1": "5ea07b090de5", "answer_pdf_sha1": "9924e7044cbb", "source_family": "moex-gov-tw", "moex": {"exam_code": "103130", "c": "803", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "103", "exam_name": "103年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01303', 'cpa', 'cpa-moex-103-78566e18', 'sub-cpa-01', NULL, 'single_choice', '甲公司於20X3年初修改退休辦法，使確定福利義務現值增加$1,794,000。甲公司目前在職員工共 80人，其相關資料如下： 至符合既得福利條件日剩餘服務年限  1  2  3  4  5 員工人數  10  20  30  10  10 假設甲公司以員工符合既得福利條件之平均剩餘服務年限攤銷前期服務成本，則20X6年應分攤之前 期服務成本為若干？', '["$0", "$156,000", "$224,250", "$624,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:14+00:00", "source_pdf_sha1": "5ea07b090de5", "answer_pdf_sha1": "9924e7044cbb", "source_family": "moex-gov-tw", "moex": {"exam_code": "103130", "c": "803", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "103", "exam_name": "103年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01304', 'cpa', 'cpa-moex-103-78566e18', 'sub-cpa-01', NULL, 'single_choice', '甲公司長期工程合約原採成本回收法（或稱零利潤法），20X6 年改採完工百分比法，相關資料 如下： 成本回收法 完工百分比法 20X6年期初在建工程   $250,000 $350,000 20X6年期末在建工程   260,000 400,000 若20X6年初原列保留盈餘為$500,000，稅率為30%，則此一長期工程損益認列方法之改變，20X6 年初之保留盈餘應作之調整為何？', '["增加$70,000", "增加$100,000", "增加$140,000", "不需調整"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:14+00:00", "source_pdf_sha1": "5ea07b090de5", "answer_pdf_sha1": "9924e7044cbb", "source_family": "moex-gov-tw", "moex": {"exam_code": "103130", "c": "803", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "103", "exam_name": "103年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01305', 'cpa', 'cpa-moex-103-78566e18', 'sub-cpa-01', NULL, 'single_choice', '甲公司於20X1年初取得乙公司15%的股權，並列為備供出售金融資產（透過其他綜合損益按公允 價值衡量之金融資產）；另於20X4年初再取得乙公司15%的股權，致對乙公司營運具重大影響力。 20X3年底甲公司帳列金融資產未實現利益為$50,000，該公司並無其他股權投資。若乙公司淨資產帳 面值皆等於公允價值，其20X4年淨利為$500,000，則投資乙公司30%股權對甲公司20X4年本期損 益之影響為何？', '["增加$75,000", "增加$100,000", "增加$150,000", "增加$200,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:14+00:00", "source_pdf_sha1": "5ea07b090de5", "answer_pdf_sha1": "9924e7044cbb", "source_family": "moex-gov-tw", "moex": {"exam_code": "103130", "c": "803", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "103", "exam_name": "103年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01306', 'cpa', 'cpa-moex-103-78566e18', 'sub-cpa-01', NULL, 'single_choice', '下列何者不會導致銷貨毛利率下降？', '["商品存貨之成本降低比例小於售價調降比例", "為增加市場競爭力而調降售價", "銷貨毛利較低之商品占整體商品之銷售比例上升", "因商品存貨成本上升而等比例調升售價"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:14+00:00", "source_pdf_sha1": "5ea07b090de5", "answer_pdf_sha1": "9924e7044cbb", "source_family": "moex-gov-tw", "moex": {"exam_code": "103130", "c": "803", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "103", "exam_name": "103年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01307', 'cpa', 'cpa-moex-103-78566e18', 'sub-cpa-01', NULL, 'single_choice', '甲公司20X1年以每股42元購入乙公司普通股股票100,000股，並分類為備供出售金融資產。該 股票於20X1年底公允價值為每股44元。甲公司於20X2年3月初以每股42元將該股票全數賣出。 下列有關此項股票交易對甲公司綜合損益表影響之敘述，何者正確？', '["對20X1年之本期淨利影響為0元", "對20X2年之本期淨利影響為0元", "對20X1年之本期綜合損益影響為0元", "對20X2年之本期綜合損益影響為0元 對20X2年之其他綜合損益影響為0元"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:14+00:00", "source_pdf_sha1": "5ea07b090de5", "answer_pdf_sha1": "9924e7044cbb", "source_family": "moex-gov-tw", "moex": {"exam_code": "103130", "c": "803", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "103", "exam_name": "103年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01308', 'cpa', 'cpa-moex-103-78566e18', 'sub-cpa-01', NULL, 'single_choice', '以下關於存貨的會計處理，何者正確：', '["附買回合約之銷貨，該商品非市場上隨時可得，賣方不認列銷貨收入，存貨仍列為資產，於取得 現金時認列負債，並於附註說明存貨抵押借款的事實", "高退貨率商品之銷貨，應待銷貨退回金額確定後，再依淨額認列銷貨收入", "分期付款的銷貨，若於貸款繳清前商品的所有權仍為賣方所擁有，此時即便商品已經交付買方， 賣方仍不得將商品自存貨中扣除", "個別認定法可適用於非大量生產且不可替換之存貨 性質與用途類似之存貨，應就(a)平均法，(b)先進先出法，(c)後進先出法三種成本公式，一致採用 相同的成本公式"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:14+00:00", "source_pdf_sha1": "5ea07b090de5", "answer_pdf_sha1": "9924e7044cbb", "source_family": "moex-gov-tw", "moex": {"exam_code": "103130", "c": "803", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "103", "exam_name": "103年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01309', 'cpa', 'cpa-moex-103-78566e18', 'sub-cpa-01', NULL, 'single_choice', '甲公司於20X1年初將當年年底到期，帳面金額為$500,000，分類為持有供交易金融資產之債券投資 售予乙公司，並提供最高賠償$40,000之違約損失保證。出售日該保證之公允價值為$25,000，乙公司 共支付$525,000予甲公司。甲公司並未移轉或保留該債券投資之幾乎所有風險及報酬，且約定乙公司 不得自由出售該債券。若20X1年底該債券投資未發生違約，關於甲公司20X1年對該債券投資應作 之會計處理，下列敘述何者正確？', '["應認列之移轉資產持續參與範圍金額共計為$25,000", "應認列之相關負債金額共計為$65,000", "應除列之金融資產金額共計為$475,000", "應認列之金融資產評價損益金額共計為$25,000 應認列之財務保證收入金額共計為$25,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:14+00:00", "source_pdf_sha1": "5ea07b090de5", "answer_pdf_sha1": "9924e7044cbb", "source_family": "moex-gov-tw", "moex": {"exam_code": "103130", "c": "803", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "103", "exam_name": "103年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01310', 'cpa', 'cpa-moex-103-78566e18', 'sub-cpa-01', NULL, 'single_choice', '高雄公司於20X1年12月31日發行可轉換公司債，面額$100,000，發行金額$110,000，直接交易 成本$2,200。已知當日不含轉換權之公司債公允價值為$90,000，轉換權之公允價值為$30,000。若發 行日負債組成部分之課稅基礎等於負債及權益組成部分原始帳面金額之合計數，稅率為 20%，對財 務報表項目之淨影響為何？', '["手續費$2,200", "應付公司債淨額$88,350", "遞延所得稅費用$3,980", "資本公積－可轉換公司債$19,450 遞延所得稅負債$3,890"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:14+00:00", "source_pdf_sha1": "5ea07b090de5", "answer_pdf_sha1": "9924e7044cbb", "source_family": "moex-gov-tw", "moex": {"exam_code": "103130", "c": "803", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "103", "exam_name": "103年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01311', 'cpa', 'cpa-moex-103-9023a44f', 'sub-cpa-02', NULL, 'essay', '甲公司為未公開發行股票之公司，實收資本額為新臺幣三億元，發行普通股三千萬股，
每股新臺幣十元，董事張三持有一百萬股。如該公司於103年6月30日召開股東
常會討論該公司董事張三之競業行為許可案時，有代表二千一百萬股之股東出席，
並經出席股東共一千八百萬股之表決權通過（包括張三所持有之一百萬股在內），
試附詳細理由回答下列問題：
依公司法相關規定，如股東李四當場表示董事張三不得參與表決，而未經主席接
受，其後股東李四於同年7月1日將其股份轉讓給王五，則王五對於該股東會之
決議，得否向法院提起撤銷之訴？（10分）
承上，若股東王五於同年 7 月 10 日向法院提起撤銷股東會決議之訴，則法院得
否駁回其請求？其審查基準為何？（10分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:14+00:00", "source_pdf_sha1": "6c84ea8819ae", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "103130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "公司法、證券交易法與商業會計法", "year": "103", "exam_name": "103年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01312', 'cpa', 'cpa-moex-103-9023a44f', 'sub-cpa-02', NULL, 'essay', 'A股份有限公司為上市公司，103年4月中旬公告該公司102年財務報告，業績表
現亮麗，獲利高於同業，吸引若干投資人進場購買該公司股票，惟102年財務報告
中有虛偽不實交易及不實現金科目，103年7月底該公司資金週轉困難，公司支票
發生退票事宜，消息揭露後，A公司股票連跌十餘日，投資人因信賴該公司製作之
不實財報，蒙受巨大損失，試問依證券交易法規定，A公司及相關人員及該公司財
報簽證會計師應負那些民事及刑事責任？請詳述之。（20分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:14+00:00", "source_pdf_sha1": "6c84ea8819ae", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "103130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "公司法、證券交易法與商業會計法", "year": "103", "exam_name": "103年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01313', 'cpa', 'cpa-moex-103-9023a44f', 'sub-cpa-02', NULL, 'essay', '試依103年6月18日商業會計法修正前之商業會計處理準則及公司法規定，說明
庫藏股之會計處理方法及股份有限公司收買庫藏股總金額之限制。（10分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:14+00:00", "source_pdf_sha1": "6c84ea8819ae", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "103130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "公司法、證券交易法與商業會計法", "year": "103", "exam_name": "103年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01314', 'cpa', 'cpa-moex-103-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '公司之經營，有顯著困難或重大損害時，法院得裁定解散，下列何者非屬必要程序之一？', '["據股東之聲請，如屬股份有限公司，則應有繼續六個月以上持有已發行股份總數百分之十以上股份之 股東提出之", "應徵詢主管機關及目的事業中央主管機關意見", "應通知公司提出答辯", "應經會計師出具報告認定公司確屬有顯著困難或重大損害之情形"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:14+00:00", "source_pdf_sha1": "6c84ea8819ae", "answer_pdf_sha1": "6ea191ad5312", "source_family": "moex-gov-tw", "moex": {"exam_code": "103130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "103", "exam_name": "103年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01315', 'cpa', 'cpa-moex-103-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '公司如為他公司有限責任股東時，其所有投資總額，除以投資為專業或公司章程另有規定或依公司法相 關規定，取得股東同意或股東會決議者外，不得超過本公司實收股本之比例為何？', '["百分之十", "百分之二十", "百分之三十", "百分之四十"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:14+00:00", "source_pdf_sha1": "6c84ea8819ae", "answer_pdf_sha1": "6ea191ad5312", "source_family": "moex-gov-tw", "moex": {"exam_code": "103130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "103", "exam_name": "103年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01316', 'cpa', 'cpa-moex-103-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '甲、乙兩家股份有限公司於設立後，依公司法第156條第8項規定進行股份交換，可排除公司法何種規 定之適用？', '["第156條第2項", "第267條第1項至第3項", "第278條第2項", "第266條"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:14+00:00", "source_pdf_sha1": "6c84ea8819ae", "answer_pdf_sha1": "6ea191ad5312", "source_family": "moex-gov-tw", "moex": {"exam_code": "103130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "103", "exam_name": "103年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01317', 'cpa', 'cpa-moex-103-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '若甲公司為未公開發行股票之股份有限公司，則關於甲公司之股份及資本，下列敘述何者錯誤？', '["公司之資本應分為股份，每股金額應歸一律", "股東之出資不以現金出資為限", "股份總數得分次發行，但第一次應發行股份不得少於股份總數四分之一", "同次發行之股份，其發行條件相同者，價格應歸一律"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:14+00:00", "source_pdf_sha1": "6c84ea8819ae", "answer_pdf_sha1": "6ea191ad5312", "source_family": "moex-gov-tw", "moex": {"exam_code": "103130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "103", "exam_name": "103年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01318', 'cpa', 'cpa-moex-103-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '甲、乙、丙、丁及戊五人擬合資設立A股份有限公司，則關於A公司董事及監察人報酬之決定，下列何 者所採用之方式合法？', '["章程規定授權董事會自行訂定董事及監察人之報酬金額，並未設一定之限制", "章程未規定董事及監察人之報酬者，由董事會自行決定董事及監察人之報酬金額，再提請股東會追認", "章程規定董事及監察人之報酬金額，授權董事會依同業標準訂定", "股東會以決議將董事及監察人報酬金額之決定，委諸董事會自行訂定"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:14+00:00", "source_pdf_sha1": "6c84ea8819ae", "answer_pdf_sha1": "6ea191ad5312", "source_family": "moex-gov-tw", "moex": {"exam_code": "103130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "103", "exam_name": "103年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01319', 'cpa', 'cpa-moex-103-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '甲為A股份有限公司（下稱A公司）之股東。A公司以修改章程為召集事由定於10月31日召開股東臨 時會，並於法定期限前寄發股東會召集通知書予各股東。甲因另有預定行程無法於10月31日親自出席， 乃出具委託書委託乙為代理人。其後，甲因行程變更，可於當日親自出席股東會，請問甲最遲應於何日 向A公司以書面撤銷其已於10月22日送達公司之委託書，始生撤銷之效力？', '["10月27日", "10月28日", "10月29日", "10月30日"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:14+00:00", "source_pdf_sha1": "6c84ea8819ae", "answer_pdf_sha1": "6ea191ad5312", "source_family": "moex-gov-tw", "moex": {"exam_code": "103130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "103", "exam_name": "103年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01320', 'cpa', 'cpa-moex-103-9023a44f', 'sub-cpa-02', NULL, 'single_choice', 'A公司設有三席董事，分別由甲、乙、丙擔任，其中甲為董事長；一席監察人，由丁擔任。若A公司章 程已規定董事會召集之通知得以電子方法為之，則對於A公司董事會召集之說明，下列敘述何者正確？', '["董事會由甲召集之，但甲請假或因故無法行使職權時，由丁召集之", "董事會召集之通知若欲以電子郵件為之，尚應經乙、丙及丁之同意", "董事會之召集，應於七日前通知甲、乙、丙三位董事，不必通知監察人丁", "董事會召集之通知雖得以電子方法為之，但不得以電話通知"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:14+00:00", "source_pdf_sha1": "6c84ea8819ae", "answer_pdf_sha1": "6ea191ad5312", "source_family": "moex-gov-tw", "moex": {"exam_code": "103130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "103", "exam_name": "103年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01321', 'cpa', 'cpa-moex-103-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '依公司法規定，下列何文件無需於股東常會承認後由董事會分發各股東？', '["營業報告書", "財務報表", "盈餘分派之決議", "虧損撥補之決議"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:14+00:00", "source_pdf_sha1": "6c84ea8819ae", "answer_pdf_sha1": "6ea191ad5312", "source_family": "moex-gov-tw", "moex": {"exam_code": "103130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "103", "exam_name": "103年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01322', 'cpa', 'cpa-moex-103-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '依公司法相關規定，A股份有限公司欲修改章程，下列之說明何者正確？', '["A公司修改章程需經股東會普通決議，否則不得為之", "A公司得以臨時動議方式提出變更章程議案", "如A公司為公開發行公司，可授權董事會為之，並報告股東會", "A公司修改章程，不得以假決議為之"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:14+00:00", "source_pdf_sha1": "6c84ea8819ae", "answer_pdf_sha1": "6ea191ad5312", "source_family": "moex-gov-tw", "moex": {"exam_code": "103130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "103", "exam_name": "103年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01323', 'cpa', 'cpa-moex-103-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '關於我國公司法上所稱之關係企業，下列敘述何者為正確？', '["分公司與本公司", "公司與他公司之執行業務股東或董事有至少三分之一相同", "具有控制從屬關係或相互投資關係之公司", "彼此有資金往來之公司"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:14+00:00", "source_pdf_sha1": "6c84ea8819ae", "answer_pdf_sha1": "6ea191ad5312", "source_family": "moex-gov-tw", "moex": {"exam_code": "103130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "103", "exam_name": "103年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01324', 'cpa', 'cpa-moex-103-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '相互投資公司之間彼此知悉有相互投資的事實者，公司法對於其所持有的股份表決權，在行使上有何規 定？', '["對表決權並無限制，由公司自由行使", "限制此等表決權全部不得行使", "不得對抗相互投資公司以外的股東", "不得超過被投資公司已發行有表決權股份的三分之一"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:14+00:00", "source_pdf_sha1": "6c84ea8819ae", "answer_pdf_sha1": "6ea191ad5312", "source_family": "moex-gov-tw", "moex": {"exam_code": "103130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "103", "exam_name": "103年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01325', 'cpa', 'cpa-moex-103-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '為使關係企業的財務業務關係可以公開透明，公司法規定在會計年度終了時公司必須編製合併財務報表， 此處之公司是指下列何種公司？', '["所有類型的公司", "所有之股份有限公司", "公開發行股票公司之控制公司", "經主管機關指定的公司"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:14+00:00", "source_pdf_sha1": "6c84ea8819ae", "answer_pdf_sha1": "6ea191ad5312", "source_family": "moex-gov-tw", "moex": {"exam_code": "103130", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "103", "exam_name": "103年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL)
